'use client';

export default function Input({ className = '', ...props }) {
  return (
    <input
      {...props}
      className={`
        border border-tertiary rounded-md w-full px-3 py-2
        text-foreground placeholder:text-tertiary/70
        dark:border-gray-600 dark:bg-tertiary/20 dark:text-white dark:placeholder:text-gray-400
        focus:outline-none focus:border-secondary focus:ring-2 focus:ring-secondary/40
        disabled:opacity-50 disabled:cursor-not-allowed
        transition-colors duration-300
        ${className}
      `}
    />
  );
}
