'use client';
import Input from '@/components/ui/Input';
import Button from '@/components/ui/Button';

export default function FlightFilters({
  filters,
  setFilters,
  search,
  setSearch,
}) {
  const updateFilter = (key, value) => {
    setFilters({ ...filters, [key]: value });
  };

  const clearFilters = () => {
    setFilters({});
    setSearch('');
  };

  return (
    <div className="mb-6 bg-surface text-foreground border border-tertiary shadow-soft rounded-lg p-6 space-y-4 md:space-y-0 md:grid md:grid-cols-3 md:gap-4 items-center">
      <Input
        type="text"
        placeholder="Buscar por código o estado (on-time, delayed, cancelled)"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      <Input
        type="text"
        placeholder="Filtrar por origen"
        value={filters.origin || ''}
        onChange={(e) => updateFilter('origin', e.target.value)}
      />

      <Input
        type="text"
        placeholder="Filtrar por destino"
        value={filters.destination || ''}
        onChange={(e) => updateFilter('destination', e.target.value)}
      />

      <div className="md:col-span-3 flex justify-end">
        <Button onClick={clearFilters} variant="secondary" size="sm">
          Limpiar filtros
        </Button>
      </div>
    </div>
  );
}
